import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // [[1,3,5],[2,4,6],[7,8]] capacity=4 -> [1,2,3,4]
        int[] result = new Solution().mergeChunksWithCapacity(
            new int[][]{{1,3,5},{2,4,6},{7,8}}, 4);
        assertArrayEquals(new int[]{1, 2, 3, 4}, result);
        assertEquals(4, result.length); // size check
    }

    @Test
    void capacityExceedsTotal() {
        // total = 5, capacity = 20 -> return all 5 sorted
        int[] result = new Solution().mergeChunksWithCapacity(
            new int[][]{{1,3},{2,4},{5}}, 20);
        assertArrayEquals(new int[]{1, 2, 3, 4, 5}, result);
        assertEquals(5, result.length); // bounded by actual total
    }

    @Test
    void capacityOne() {
        // only the single smallest element
        int[] result = new Solution().mergeChunksWithCapacity(
            new int[][]{{5,10},{1,8},{3}}, 1);
        assertArrayEquals(new int[]{1}, result);
        assertEquals(1, result.length);
    }

    @Test
    void emptyChunkAmongOthers() {
        // chunk1 is empty — must not crash; collect 3 elements
        int[] result = new Solution().mergeChunksWithCapacity(
            new int[][]{{1,4,7},{},{2,5,8}}, 3);
        assertArrayEquals(new int[]{1, 2, 4}, result);
        assertEquals(3, result.length);
    }

    @Test
    void emptyChunksArray() {
        // no chunks at all -> empty result regardless of capacity
        int[] result = new Solution().mergeChunksWithCapacity(new int[][]{}, 5);
        assertArrayEquals(new int[]{}, result);
        assertEquals(0, result.length);
    }

    @Test
    void tiebreakerWithCapacity() {
        // chunk0 and chunk1 both have 3 at front; capacity=2 -> [3,3]
        // lower chunk index first for the first 3
        int[] result = new Solution().mergeChunksWithCapacity(
            new int[][]{{3,9},{3,7}}, 2);
        assertArrayEquals(new int[]{3, 3}, result);
        assertEquals(2, result.length);
    }

    @Test
    void singleChunk() {
        // k=1 degenerate: prefix slice of a single sorted chunk
        int[] result = new Solution().mergeChunksWithCapacity(
            new int[][]{{10, 20, 30, 40}}, 3);
        assertArrayEquals(new int[]{10, 20, 30}, result);
    }
}
